+    /// Escape single quotes for JavaScript string literals
+    fn escapeSingleQuotes(input: []const u8, buf: []u8) []const u8 {
+        var j: usize = 0;
+        for (input) |c| {
+            if (j + 2 > buf.len) break;
+            if (c == '\'') {
+                buf[j] = '\\';
+                buf[j + 1] = '\'';
+                j += 2;
+            } else if (c == '\\') {
+                buf[j] = '\\';
+                buf[j + 1] = '\\';
+                j += 2;
+            } else {
+                buf[j] = c;
+                j += 1;
+            }
+        }
+        return buf[0..j];
+    }
